// rateLimiter.js
'use strict';

/**
 * Creates a true sliding-window rate limiting middleware.
 *
 * Unlike a fixed-window limiter (which resets a counter at fixed intervals and
 * allows bursts at window boundaries), this tracks the timestamp of every
 * request per client and, on each incoming request, discards timestamps older
 * than `windowMs`. The decision is always made against the *trailing* window
 * ending at "now", so the window slides continuously with each request.
 *
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]    Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]   Max requests allowed per window.
 * @returns {Function} Express middleware, augmented with a `.close()` method
 *                     that clears the internal cleanup timer.
 */
function createRateLimiter(options = {}) {
  const windowMs = options.windowMs ?? 60000;
  const maxRequests = options.maxRequests ?? 100;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]>  -> sorted ascending list of request timestamps (ms)
  const hits = new Map();

  /**
   * Drop all timestamps that fall outside the trailing window [now - windowMs, now].
   * Timestamps are appended in chronological order, so we can splice from the front.
   * @returns {number[]} the in-place-trimmed array
   */
  function prune(timestamps, now) {
    const cutoff = now - windowMs;
    let i = 0;
    while (i < timestamps.length && timestamps[i] <= cutoff) {
      i++;
    }
    if (i > 0) timestamps.splice(0, i);
    return timestamps;
  }

  function middleware(req, res, next) {
    // NOTE: `req.ip` depends on Express's "trust proxy" setting. Behind a proxy
    // or load balancer, req.ip is the proxy's address unless you enable it:
    //   app.set('trust proxy', true)   // or a specific hop count / subnet
    // With trust proxy on, Express derives req.ip from X-Forwarded-For. Without
    // it, every proxied client shares one IP and gets rate-limited together.
    // Only trust the header when you actually sit behind a proxy you control,
    // otherwise clients can spoof X-Forwarded-For to evade limits.
    const key = req.ip || req.socket?.remoteAddress || 'unknown';
    const now = Date.now();

    let timestamps = hits.get(key);
    if (!timestamps) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    prune(timestamps, now);

    const reset = Math.ceil((now + windowMs) / 1000); // epoch seconds

    if (timestamps.length >= maxRequests) {
      // Over the limit. The window frees up when the OLDEST tracked request
      // ages out, i.e. at timestamps[0] + windowMs.
      const retryAfterMs = timestamps[0] + windowMs - now;
      const retryAfter = Math.max(1, Math.ceil(retryAfterMs / 1000));

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil((timestamps[0] + windowMs) / 1000));
      res.setHeader('Retry-After', retryAfter);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter,
      });
      return; // Do NOT call next()
    }

    // Allowed: record this request and pass through.
    timestamps.push(now);

    const remaining = Math.max(0, maxRequests - timestamps.length);
    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', remaining);
    res.setHeader('X-RateLimit-Reset', reset);

    next();
  }

  // --- Memory management -----------------------------------------------------
  // Periodically evict clients with no activity inside the current window so the
  // Map doesn't grow unbounded as IPs come and go.
  const cleanupTimer = setInterval(() => {
    const now = Date.now();
    for (const [key, timestamps] of hits) {
      prune(timestamps, now);
      if (timestamps.length === 0) {
        hits.delete(key);
      }
    }
  }, 60000);

  // Don't let the cleanup timer keep the Node process alive on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  /** Stop the cleanup timer and release tracked state. */
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
