   * Central store: ip → sorted-ascending array of request timestamps (ms).
   * @type {Map<string, number[]>}
   */
  const store = new Map();

  // ── Helpers ──────────────────────────────────────────────────────────────

  /**
   * Binary search: returns the index of the first element strictly greater
   * than `cutoff`. Elements at indices < result are expired.
   *
   * O(log n) — pays off for high-traffic IPs that accumulate many in-window
   * timestamps before the window slides past them.
   *
   * @param {number[]} arr
   * @param {number}   cutoff  - Timestamps <= cutoff are expired.
   * @returns {number}
   */
  function firstValidIndex(arr, cutoff) {
    let lo = 0;
    let hi = arr.length;
    while (lo < hi) {
      const mid = (lo + hi) >>> 1; // unsigned right-shift avoids float overflow
      if (arr[mid] <= cutoff) {
        lo = mid + 1;
      } else {
        hi = mid;
      }
    }
    return lo;
  }

