   * Removes all timestamps <= cutoff from the front of `arr`.
   * Returns the same array reference if nothing was trimmed (avoids allocation).
   *
   * @param {number[]} arr
   * @param {number}   cutoff
   * @returns {number[]}
   */
  function slideWindow(arr, cutoff) {
    const idx = firstValidIndex(arr, cutoff);
    return idx === 0 ? arr : arr.slice(idx);
