        error:      'Rate limit exceeded',
        retryAfter: retryAfterSecs,
      });
    }

    // ── ALLOWED ───────────────────────────────────────────────────────────
    //
    // Appending `now` maintains ascending order since it is always the largest
    // value in the array.

    live.push(now);
    store.set(ip, live);

    const remaining = maxRequests - live.length; // slots still available

    // X-RateLimit-Reset: epoch seconds when the oldest in-window request ages
    // out — i.e. when the next slot will open even if the client keeps
    // hammering at full speed. Gives clients a concrete "wait until" time.
