 * Creates an Express middleware that enforces a sliding-window rate limit per IP.
 *
 * @param {Object} [options]
 * @param {number} [options.windowMs=60000]   - Size of the sliding window in milliseconds
 * @param {number} [options.maxRequests=100]  - Max requests allowed within the window
 * @returns {Function & { close: Function }} Express middleware function.
 *          The returned function also has a `.close()` method that stops the internal
 *          cleanup timer (call this on server shutdown to allow clean process exit).
 */
function createRateLimiter(options = {}) {
  const windowMs = Number.isFinite(options.windowMs) && options.windowMs > 0
    ? Math.floor(options.windowMs)
    : 60000;

  const maxRequests = Number.isFinite(options.maxRequests) && options.maxRequests > 0
    ? Math.floor(options.maxRequests)
    : 100;

  /** @type {Map<string, number[]>} ip -> array of request timestamps (ms since epoch) */
  const requests = new Map();

  // Periodic cleanup: every 60 seconds, drop IPs that have no recent activity.
  // This prevents unbounded memory growth when many different IPs hit the server.
  const CLEANUP_INTERVAL_MS = 60000;

  const cleanupInterval = setInterval(() => {
    const now = Date.now();
    const cutoff = now - windowMs;

    for (const [ip, timestamps] of requests.entries()) {
      // Keep only timestamps still inside the current window
      const recent = timestamps.filter(ts => ts > cutoff);

      if (recent.length === 0) {
        requests.delete(ip);
      } else if (recent.length < timestamps.length) {
        // Only write back if we actually removed entries (avoids unnecessary churn)
        requests.set(ip, recent);
      }
