  // Usage: const limiter = createRateLimiter();  app.use(limiter);  ...  limiter.close();
  rateLimitMiddleware.close = close;

  // Exposed for testing / introspection only (not part of public API)
  rateLimitMiddleware._store = requests;

  return rateLimitMiddleware;
}

